const express = require('express');
const service = require('./service');
const { errorHandler } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  try {
    const project = await service.createProject(req.body);
    res.status(201).json({ project });
  } catch (error) {
    errorHandler(res, error);
  }
});

router.get('/', async (req, res) => {
  try {
    const projects = await service.getAllProjects();
    res.status(200).json({ projects });
  } catch (error) {
    errorHandler(res, error);
  }
});

router.get('/:projectId', async (req, res) => {
  try {
    const project = await service.getProjectById(req.params.projectId);
    res.status(200).json({ project });
  } catch (error) {
    errorHandler(res, error);
  }
});

router.use('/:projectId/members', require('../members/routes'));
router.use('/:projectId/tasks', require('../tasks/routes'));

module.exports = router;

const { generateId } = require('../../lib/id');
const projects = {};

function createProject({ name }) {
  if (!name) throw { code: 'invalid_input', message: 'Name is required' };
  const id = generateId();
  if (Object.values(projects).some(p => p.name === name)) throw { code: 'duplicate_project', message: 'Project with this name already exists' };
  projects[id] = { id, name };
  return projects[id];
}

function getAllProjects() {
  return Object.values(projects);
}

function getProjectById(id) {
  const project = projects[id];
  if (!project) throw { code: 'not_found', message: 'Project not found' };
  return project;
}

module.exports = { createProject, getAllProjects, getProjectById };

const express = require('express');
const service = require('./service');
const { errorHandler } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  try {
    const member = await service.addMember(req.params.projectId, req.body);
    res.status(201).json({ member });
  } catch (error) {
    errorHandler(res, error);
  }
});

router.get('/', async (req, res) => {
  try {
    const members = await service.getAllMembers(req.params.projectId);
    res.status(200).json({ members });
  } catch (error) {
    errorHandler(res, error);
  }
});

module.exports = router;

const projectsService = require('../projects/service');
const { generateId } = require('../../lib/id');

const members = {};

function addMember(projectId, { userId, role }) {
  if (!userId || !role) throw { code: 'invalid_input', message: 'UserId and role are required' };
  projectsService.getProjectById(projectId);
  const id = generateId();
  if (members[projectId] && members[projectId].some(m => m.userId === userId)) throw { code: 'duplicate_member', message: 'Member with this userId already exists in the project' };
  if (!members[projectId]) members[projectId] = [];
  const member = { id, userId, role };
  members[projectId].push(member);
  return member;
}

function getAllMembers(projectId) {
  projectsService.getProjectById(projectId);
  return members[projectId] || [];
}

module.exports = { addMember, getAllMembers };

