router.patch('/:taskId', async (req, res) => {
  try {
    const task = await service.updateTask(req.params.projectId, req.params.taskId, req.body);
    res.status(200).json({ task });
  } catch (error) {
    errorHandler(res, error);
  }
});

router.use('/:taskId/comments', require('../comments/routes'));

module.exports = router;

const projectsService = require('../projects/service');
const { generateId } = require('../../lib/id');

const tasks = {};

function createTask(projectId, { title }) {
  if (!title) throw { code: 'invalid_input', message: 'Title is required' };
  projectsService.getProjectById(projectId);
  const id = generateId();
  if (!tasks[projectId]) tasks[projectId] = [];
  const task = { id, title, status: 'pending' };
  tasks[projectId].push(task);
  return task;
}

function getAllTasks(projectId, status) {
  projectsService.getProjectById(projectId);
  if (!tasks[projectId]) return [];
  return status ? tasks[projectId].filter(t => t.status === status) : tasks[projectId];
}

function updateTask(projectId, taskId, { status }) {
  projectsService.getProjectById(projectId);
  const task = tasks[projectId] && tasks[projectId].find(t => t.id === taskId);
  if (!task) throw { code: 'not_found', message: 'Task not found' };
  if (status && ['pending', 'done'].includes(status)) {
    task.status = status;
  }
  return task;
}

module.exports = { createTask, getAllTasks, updateTask };

const express = require('express');
const service = require('./service');
const { errorHandler } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  try {
    const comment = await service.addComment(req.params.projectId, req.params.taskId, req.body);
    res.status(201).json({ comment });
  } catch (error) {
    errorHandler(res, error);
  }
});

router.get('/', async (req, res) => {
  try {
    const comments = await service.getAllComments(req.params.projectId, req.params.taskId);
    res.status(200).json({ comments });
  } catch (error) {
    errorHandler(res, error);
  }
});

module.exports = router;

const tasksService = require('../tasks/service');
const { generateId } = require('../../lib/id');

const comments = {};

function addComment(projectId, taskId, { message }) {
  if (!message) throw { code: 'invalid_input', message: 'Message is required' };
  tasksService.getProjectById(projectId);
  tasksService.getTaskById(projectId, taskId);
  const id = generateId();
  if (!comments[taskId]) comments[taskId] = [];
  const comment = { id, message };
  comments[taskId].push(comment);
  return comment;
}

function getAllComments(projectId, taskId) {
  tasksService.getProjectById(projectId);
  tasksService.getTaskById(projectId, taskId);
  return comments[taskId] || [];
}

module.exports = { addComment, getAllComments };

function errorHandler(res, error) {
  const code = error.code || 'internal_error';
  const message = error.message || 'Internal server error';
  res.status(code === 'not_found' ? 404 : code === 'invalid_input' ? 400 : 500).json({ code, message });
}

module.exports = { errorHandler };

let currentId = 1;

function generateId() {
  return (currentId++).toString();
}

module.exports = { generateId };
